-- chilli — NO soy sauce). Run in Supabase SQL Editor. Idempotent upsert.

INSERT INTO public.recipes (id,title,subtitle,emoji,image_url,tags,meal,categories,diet,is_kids,prep_minutes,cook_minutes,servings,nutrition,ingredients,dressing,base_ingredients,steps,i18n) VALUES (
 'herb-tofu-smashed-potatoes', 'Herb Tofu & Smashed Potatoes', 'Fresh coriander, lime & green chilli — Honest Greens style', '🥔', 'https://v3b.fal.media/files/b/0a9cf816/wseyWrjVP3cAhvQSiBoPP_6b5594ea40d64929a5955690a7926805.jpg',
 ARRAY['Vegan','Gluten-free'], ARRAY['Main Course'], ARRAY['Pfannengericht'], ARRAY['Vegan','Gluten-free'],
 false, 15, 30, 2,
 '{"fat":18,"kcal":460,"carbs":48,"fiber":6,"protein":22}'::jsonb, '[{"name":"Firm tofu","emoji":"🟨","amount":"300g"},{"name":"Baby potatoes","emoji":"🥔","amount":"400g"},{"emoji":"🌿","name":"Fresh coriander (cilantro)","amount":"20g"},{"name":"Garlic","emoji":"🧄","amount":"3 cloves"},{"emoji":"🍋","name":"Lime","amount":"1 pc"},{"emoji":"🌶️","name":"Fresh green chilli","amount":"1 pc"},{"name":"Spinach","emoji":"🥬","amount":"60g"}]'::jsonb, '[{"name":"Tamari","emoji":"🫙","amount":"2 tbsp"}]'::jsonb, '["Olive oil","Salt & pepper"]'::jsonb, '[{"num":1,"tip":null,"ings":["🟨 Firm tofu · 300g","🫒 Olive oil · 2 tbsp","🍋 Lime · 1 pc","🌿 Fresh coriander · 20g","🧄 Garlic · 3 cloves","🌶️ Green chilli · 1 pc"],"text":"Press tofu for 15 minutes between kitchen paper. Cube and marinate in olive oil, lime juice, chopped fresh coriander, minced garlic and finely chopped green chilli for 10 minutes.","title":"Press & marinate the tofu","kidsHelp":null},{"num":2,"tip":null,"ings":["🥔 Baby potatoes · 400g"],"text":"Boil baby potatoes in salted water for 15 minutes until just tender. Drain well.","title":"Boil the potatoes","kidsHelp":null},{"num":3,"tip":"The smashing is what makes them extra crispy!","ings":["🥔 Baby potatoes · 400g"],"text":"Place potatoes on a baking tray. Smash each one with the bottom of a glass. Drizzle with olive oil and roast at 220°C for 20 minutes until golden and crispy.","title":"Smash & roast","kidsHelp":"Kids love smashing the potatoes! 🧒"},{"num":4,"tip":null,"ings":["🟨 Firm tofu · 300g"],"text":"Cook tofu in olive oil over high heat for 3–4 minutes per side until crispy and golden.","title":"Fry the tofu","kidsHelp":null},{"num":5,"tip":null,"ings":["🥬 Spinach · 60g","🌿 Fresh herbs · 20g"],"text":"Wilt spinach in the same pan for 1 minute. Serve potatoes and tofu with spinach. Top with fresh coriander and a squeeze of lime.","title":"Finish & serve","kidsHelp":null}]'::jsonb, '{"es":{"title":"Tofu a las hierbas y patatas aplastadas","subtitle":"Cilantro fresco, lima y chile verde — al estilo Honest Greens","ingredients":["Tofu firme","Patatas pequeñas","Cilantro fresco","Ajo","Lima","Chile verde fresco","Espinacas"],"base":["Aceite de oliva","Sal y pimienta"],"dressing":["Tamari"],"steps":[{"tip":null,"ings":["🟨 Tofu firme · 300g","🫒 Aceite de oliva · 2 cdas","🍋 Lima · 1 ud","🌿 Cilantro fresco · 20g","🧄 Ajo · 3 dientes","🌶️ Chile verde · 1 ud"],"text":"Prensa el tofu 15 minutos entre papel de cocina. Córtalo en dados y marínalo 10 minutos en aceite de oliva, zumo de lima, cilantro fresco picado, ajo picado y chile verde finamente picado.","title":"Prensa y marina el tofu","kidsHelp":null},{"tip":null,"ings":["🥔 Patatas pequeñas · 400g"],"text":"Cuece las patatas pequeñas en agua con sal 15 minutos hasta que estén tiernas. Escurre bien.","title":"Cuece las patatas","kidsHelp":null},{"tip":"¡Aplastarlas es lo que las hace extra crujientes!","ings":["🥔 Patatas pequeñas · 400g"],"text":"Coloca las patatas en una bandeja de horno. Aplasta cada una con el fondo de un vaso. Riega con aceite de oliva y asa a 220°C 20 minutos hasta que estén doradas y crujientes.","title":"Aplasta y asa","kidsHelp":"¡A los niños les encanta aplastar las patatas! 🧒"},{"tip":null,"ings":["🟨 Tofu firme · 300g"],"text":"Cocina el tofu en aceite de oliva a fuego alto 3–4 minutos por lado hasta que esté crujiente y dorado.","title":"Fríe el tofu","kidsHelp":null},{"tip":null,"ings":["🥬 Espinacas · 60g","🌿 Hierbas frescas · 20g"],"text":"Rehoga las espinacas 1 minuto en la misma sartén. Sirve las patatas y el tofu con las espinacas. Corona con cilantro fresco y un chorrito de lima.","title":"Termina y sirve","kidsHelp":null}]},"fr":{"title":"Tofu aux herbes & pommes de terre écrasées","subtitle":"Coriandre fraîche, citron vert & piment vert — façon Honest Greens","ingredients":["Tofu ferme","Pommes de terre grenaille","Coriandre fraîche","Ail","Citron vert","Piment vert frais","Épinards"],"base":["Huile d''olive","Sel & poivre"],"dressing":["Tamari"],"steps":[{"tip":null,"ings":["🟨 Tofu ferme · 300g","🫒 Huile d''olive · 2 c. à s.","🍋 Citron vert · 1 pc","🌿 Coriandre fraîche · 20g","🧄 Ail · 3 gousses","🌶️ Piment vert · 1 pc"],"text":"Presser le tofu 15 minutes entre du papier absorbant. Couper en dés et mariner 10 minutes dans l''huile d''olive, le jus de citron vert, la coriandre fraîche hachée, l''ail émincé et le piment vert finement haché.","title":"Presser et mariner le tofu","kidsHelp":null},{"tip":null,"ings":["🥔 Pommes de terre grenaille · 400g"],"text":"Cuire les pommes de terre grenaille à l''eau salée 15 minutes jusqu''à ce qu''elles soient tendres. Bien égoutter.","title":"Cuire les pommes de terre","kidsHelp":null},{"tip":"C''est l''écrasage qui les rend extra croustillantes !","ings":["🥔 Pommes de terre grenaille · 400g"],"text":"Disposer les pommes de terre sur une plaque. Écraser chacune avec le fond d''un verre. Arroser d''huile d''olive et rôtir à 220°C 20 minutes jusqu''à ce qu''elles soient dorées et croustillantes.","title":"Écraser et rôtir","kidsHelp":"Les enfants adorent écraser les pommes de terre ! 🧒"},{"tip":null,"ings":["🟨 Tofu ferme · 300g"],"text":"Cuire le tofu à l''huile d''olive à feu vif 3–4 minutes par face jusqu''à ce qu''il soit croustillant et doré.","title":"Frire le tofu","kidsHelp":null},{"tip":null,"ings":["🥬 Épinards · 60g","🌿 Herbes fraîches · 20g"],"text":"Faire tomber les épinards 1 minute dans la même poêle. Servir les pommes de terre et le tofu avec les épinards. Parsemer de coriandre fraîche et arroser de citron vert.","title":"Finir et servir","kidsHelp":null}]},"de":{"title":"Kräutertofu & gestampfte Kartoffeln","subtitle":"Frischer Koriander, Limette & grüne Chili — im Honest-Greens-Stil","ingredients":["Fester Tofu","Drillinge (kleine Kartoffeln)","Frischer Koriander","Knoblauch","Limette","Frische grüne Chili","Spinat"],"base":["Olivenöl","Salz & Pfeffer"],"dressing":["Tamari"],"steps":[{"tip":null,"ings":["🟨 Fester Tofu · 300g","🫒 Olivenöl · 2 EL","🍋 Limette · 1 St.","🌿 Frischer Koriander · 20g","🧄 Knoblauch · 3 Zehen","🌶️ Grüne Chili · 1 St."],"text":"Tofu 15 Minuten zwischen Küchenpapier pressen. In Würfel schneiden und 10 Minuten in Olivenöl, Limettensaft, gehacktem frischem Koriander, gehacktem Knoblauch und fein gehackter grüner Chili marinieren.","title":"Tofu pressen & marinieren","kidsHelp":null},{"tip":null,"ings":["🥔 Drillinge · 400g"],"text":"Kleine Kartoffeln in Salzwasser 15 Minuten weich kochen. Gut abgießen.","title":"Kartoffeln kochen","kidsHelp":null},{"tip":"Das Flachdrücken macht sie extra knusprig!","ings":["🥔 Drillinge · 400g"],"text":"Kartoffeln auf ein Backblech legen. Jede mit dem Boden eines Glases flach drücken. Mit Olivenöl beträufeln und bei 220°C 20 Minuten goldbraun und knusprig rösten.","title":"Stampfen und rösten","kidsHelp":"Kinder lieben es, die Kartoffeln zu zerdrücken! 🧒"},{"tip":null,"ings":["🟨 Fester Tofu · 300g"],"text":"Tofu in Olivenöl bei hoher Hitze 3–4 Minuten pro Seite knusprig und goldbraun braten.","title":"Tofu braten","kidsHelp":null},{"tip":null,"ings":["🥬 Spinat · 60g","🌿 Frische Kräuter · 20g"],"text":"Spinat in derselben Pfanne 1 Minute zusammenfallen lassen. Kartoffeln und Tofu mit Spinat servieren. Mit frischem Koriander und einem Spritzer Limette toppen.","title":"Fertigstellen & servieren","kidsHelp":null}]}}'::jsonb
)
